//AOC2019 D16


//base 0,1,0,-1
function getPattern(idx, len) {
    let base = [0,1,0,-1].flatMap(v => Array(idx+1).fill(v));
    return Array(Math.ceil(len / base.length) + 1).fill(base).flat().slice(1, 1 + len);
}

// console.log(getPattern(1, 15));

function fft(str) {
    let list = str.split('').map(s => parseInt(s, 10));
    return list.map((v,i) => {
        let pattern = getPattern(i, list.length);
        let sum = list.reduce((a, c, i) => a + c * pattern[i], 0);
        return Math.abs(sum % 10);
    }).join('');
}

function phases(str, num) {
    for(let i=0; i<num; i++) {
        str = fft(str);
    }
    return str;
}

console.log(phases('80871224585914546619083218645595', 100).slice(0,8)); //24176176.
console.log(phases('19617804207202209144916044189917', 100).slice(0,8)); //73745418.
console.log(phases('69317163492948606335995924319873', 100).slice(0,8)); //52432133.
